(function($){"use strict";var GiveWPMigration={importId:null,batchTimer:null,$wrap:null,$startBtn:null,$progress:null,$progressBar:null,$progressStatus:null,$results:null,$dryRunResults:null,$error:null,totalItems:0,processedItems:0,init:function(){this.$wrap=$(".charitable-givewp-migration-wrap");this.$startBtn=$("#charitable-givewp-migrate-start");this.$progress=this.$wrap.find(".migration-progress");this.$progressBar=this.$wrap.find(".progress-bar-inner");this.$progressStatus=this.$wrap.find(".progress-status");this.$results=this.$wrap.find(".migration-results");this.$dryRunResults=this.$wrap.find(".migration-dry-run-results");this.$error=this.$wrap.find(".migration-error");if(!this.$wrap.length){return}this.$startBtn.on("click",$.proxy(this.onStart,this))},onStart:function(e){e.preventDefault();var campaigns=$('input[name="givewp_import_campaigns"]').is(":checked"),donations=$('input[name="givewp_import_donations"]').is(":checked"),dryRun=$('input[name="givewp_dry_run"]').is(":checked"),i18n=charitable_givewp_migration.i18n,confirmMsg;if(!campaigns&&!donations){alert("Please select at least one import type.");return}confirmMsg=dryRun?i18n.confirm_dry:i18n.confirm;if(!confirm(confirmMsg)){return}this.$results.hide();this.$dryRunResults.hide();this.$error.hide().text("");this.$progress.show();this.$progressBar.css("width","0%");this.$progressStatus.text(i18n.starting);this.$startBtn.prop("disabled",true);this.processedItems=0;$.ajax({url:charitable_givewp_migration.ajax_url,type:"POST",data:{action:"charitable_givewp_import_start",nonce:charitable_givewp_migration.nonce,campaigns:campaigns?1:0,donations:donations?1:0,dry_run:dryRun?1:0},success:$.proxy(function(response){if(response.success){this.importId=response.data.import_id;this.totalItems=0;if(campaigns&&response.data.counts.campaigns){this.totalItems+=parseInt(response.data.counts.campaigns,10)}if(donations&&response.data.counts.donations){this.totalItems+=parseInt(response.data.counts.donations,10)}this.processBatch()}else{this.showError(response.data.message||i18n.error)}},this),error:$.proxy(function(){this.showError(i18n.error)},this)})},processBatch:function(){var self=this;$.ajax({url:charitable_givewp_migration.ajax_url,type:"POST",data:{action:"charitable_givewp_import_batch",nonce:charitable_givewp_migration.nonce,import_id:this.importId},success:function(response){if(!response.success){self.showError(response.data.message||charitable_givewp_migration.i18n.error);return}var data=response.data,results=data.results,total=0,done=0,i18n=charitable_givewp_migration.i18n;if(results.campaigns){total+=results.campaigns.imported+results.campaigns.skipped+results.campaigns.errors}if(results.donations){total+=results.donations.imported+results.donations.skipped+results.donations.errors}self.processedItems=total;var pct=self.totalItems>0?Math.min(total/self.totalItems*100,100):0;self.$progressBar.css("width",pct+"%");if(data.current_phase){var phaseName=i18n[data.current_phase]||data.current_phase;self.$progressStatus.text(i18n.importing.replace("%1$s",phaseName).replace("%2$d",total).replace("%3$d",self.totalItems))}if("complete"===data.status){self.$progressBar.css("width","100%");self.$progressStatus.text(data.dry_run?i18n.dry_complete:i18n.complete);self.$startBtn.prop("disabled",false);if(data.dry_run){self.showDryRunResults(results)}else{self.showResults(results)}}else{self.batchTimer=setTimeout(function(){self.processBatch()},500)}},error:function(){self.showError(charitable_givewp_migration.i18n.error)}})},showResults:function(results){var $tbody=this.$results.find("tbody");$tbody.empty();if(results.campaigns){$tbody.append("<tr><td>Campaigns</td><td>"+results.campaigns.imported+"</td><td>"+results.campaigns.skipped+"</td><td>"+results.campaigns.errors+"</td></tr>")}if(results.donations){$tbody.append("<tr><td>Donations</td><td>"+results.donations.imported+"</td><td>"+results.donations.skipped+"</td><td>"+results.donations.errors+"</td></tr>")}this.$results.show()},showDryRunResults:function(results){var $tbody=this.$dryRunResults.find("tbody");$tbody.empty();if(results.campaigns){$tbody.append("<tr><td>Campaigns</td><td>"+results.campaigns.imported+"</td><td>"+results.campaigns.skipped+"</td><td>"+results.campaigns.errors+"</td></tr>")}if(results.donations){$tbody.append("<tr><td>Donations</td><td>"+results.donations.imported+"</td><td>"+results.donations.skipped+"</td><td>"+results.donations.errors+"</td></tr>")}this.$dryRunResults.show()},showError:function(message){this.$error.text(message).show();this.$startBtn.prop("disabled",false);this.$progressStatus.text("");if(this.batchTimer){clearTimeout(this.batchTimer)}}};$(document).ready(function(){GiveWPMigration.init()})})(jQuery);